var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"좋아…… 이제 다 됐어요.","JPN":"よし……できました。","ENG":"All right... It’s all done.","TWN":"OK……大功告成！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"음? 자, 잠깐 이건……!?","JPN":"うん？　ちょ、ちょっと、これって……！？","ENG":"Mm? W-wait... Is this...?","TWN":"嗯？這…這是……！？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……미리네?","JPN":"……マリ？","ENG":"…Rinae?","TWN":"……宓璃奈？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이, 이기 뭐꼬!?","JPN":"な、なんやこれ！？","ENG":"W-what in the name of...!","TWN":"你…你幹啥你！？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니 미쳤나!? 갑자기 와 내를 그리는 긴데!? 니 내한테 반한기가!?","JPN":"あんた、頭どうかしたん！？　なんでいきなりウチを描くん！？　ウチに惚れたんか！？","ENG":"Have you lost it, kid? What are ya fooling about, huh?! Are you into me or somethin’?","TWN":"你瘋啦？為啥突然要畫我！？你是愛上我喔？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"무, 무슨 소리에요! 그럴 리가 없잖아요! 좀 더 자세히 보시라고요!","JPN":"な、何を言ってるんですか！　そんなわけないでしょう！　もっとちゃんと見てください！","ENG":"W-what?! Don’t be ridiculous! Look closer!","TWN":"胡…胡說八道！想也知道不可能！你再看仔細一點！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"호오, 이건 스트리트 카운터의 인게임 일러스트랑 스타일이 거의 흡사한데요?","JPN":"ほう、これはストリート・カウンターのインゲームイラストとほぼ同じスタイルだね。","ENG":"Ho-oh, this looks extremely similar to the in-game illustrations of Street Counter.","TWN":"哇喔，和街頭制裁者遊戲中的立繪感覺好像喔？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실력이 대단하네요, 조금만 다듬으면 바로 인게임 리소스로도 사용해도 괜찮을 정도에요.","JPN":"素晴らしい実力だ。もう少しブラッシュアップすれば、すぐインゲームイラストとして使ってもいいくらいだよ。","ENG":"You're extremely talented. A bit more tidying up, and it’ll be ready to be used as a resource.","TWN":"很厲害呢，只需要再微調一下，直接拿來當作遊戲素材似乎也沒問題。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L16_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"본 적 있어……. 이 그림체.","JPN":"見たことある……この画風。","ENG":"I’ve seen it before... This art style.","TWN":"我有看過……這個畫風。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이거 <color=#ffd34c>박스X</color>의 그림이야…… 오에카키에서 격투 게임 팬아트를 그리는.","JPN":"これ、<color=#ffd34c>ダンボールX</color>の絵……お絵かきで格ゲーのファンアート描いてる。","ENG":"This is <color=#ffd34c>Box X</color>... On Oekaki, he uploads fighting game fanart.","TWN":"這是<color=#ffd34c>BOX X</color>的畫風……他都會在線上繪圖版發表他的格鬥遊戲二創圖。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에엥? 박스X라고? 금마 존잘 일러레 아이가?","JPN":"ええっ？　ダンボールXやて？　あのめっちゃ絵がうまいイラストレーター？","ENG":"Eh? Box X? Ain’t he some super prodigy or something?","TWN":"你說啥？BOX X？很會畫人物的繪師？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그런 일러레가 이런 얼라라고? 내는 좀 더 어른인 줄 알았는데?","JPN":"あのイラストレーターがこんなガキなん？　ウチはもっと大人やと思っとったわ。","ENG":"You're tellin' me that this kid right here is Box X? I thought he was a grownup!","TWN":"你說這個小朋友就是他？我還以為會比他再大一點呢？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"앗!? 그럼, 설마 박스X라는 닉네임도 스트리트 카운터에서 따온기가?","JPN":"あっ！？　じゃあ、まさかダンボールXってネームもストリート・カウンターから取ってきたん？","ENG":"Oh?! Is the name \\"Box X\\" an homage to Street Counter?!","TWN":"嗯！？該不會BOX X這個暱稱也是模仿街頭制裁者的嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"맞아요, 제가 그림을 시작하게 된 게 바로 스트리트 카운터 때문이었거든요.","JPN":"そうですよ、僕が絵を描き始めたきっかけがストリート・カウンターでしたから。","ENG":"Yes, Street Counter was the sole reason why I started drawing.","TWN":"沒錯，街頭制裁者就是我的繪畫啟蒙。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그래서 스트리트 카운터는 저에게 무척 소중한 게임이에요.","JPN":"なのでストリート・カウンターは僕にとって、とても大事なゲームなんです。","ENG":"It’s that precious to me.","TWN":"所以街頭制裁者對我來說是非常重要的遊戲。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그 좋아하는 마음만큼은 여기 있는 누구에게도 지지 않는다고요.","JPN":"その気持ちだけはここにいる誰にも負けません。","ENG":"My love and passion for Street Counter wouldn’t be less than anyone here.","TWN":"我敢說，我對\\"街制\\"的熱愛是不會輸給任何人的！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……꼬맹이.","JPN":"……じゃりんこ。","ENG":"...Kiddo.","TWN":"……小朋友。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군요……. 제가 제작한 게임을 소중하게 생각해주셔서 감사하군요.","JPN":"なるほど……私が制作したゲームを大事に思ってくれてありがとう。","ENG":"I see... Thank you for treasuring my game so much.","TWN":"原來如此……謝謝你這麼熱愛我製作的遊戲。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 저희 학생들도 박스 군 못지 않게, 게임에 대한 열정이 있답니다.","JPN":"でもね、私の生徒たちもダンボール君に劣らないくらい、ゲームへの情熱を持っているんだよ。","ENG":"But my students are passionate about the game as much as you are.","TWN":"不過我相信，學生們對於這款遊戲的熱愛也不亞於你。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 박스 군에게 한가지 제안을 드려볼까 하는데 괜찮을까요?","JPN":"そこでダンボール君に一つ提案したいことがあるんだけど、いいかな。","ENG":"Which is why I would like to make an offer, Box.","TWN":"所以我想跟你商量一下，你願意聽嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"어떤 제안인데요?","JPN":"どんな提案でしょうか？","ENG":"What offer?","TWN":"要商量什麼？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우선, 박스 군이 정성스레 그린 이 캐릭터를 다같이 힘을 모아 움직여 보는 건 어떨까요?","JPN":"まず、ダンボール君が丁寧に描いたこのキャラを、みんなで力を合わせて動かしてみるのはどうだろう？","ENG":"First, why don’t we try animating this character together?","TWN":"首先，集結大家的力量，一起讓你用心畫的角色動起來怎麼樣？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네? 제 그림을 움직이게 한다고요?","JPN":"はい？　僕の絵を動かすんですか？","ENG":"What? You want to animate my drawing?","TWN":"什麼？要讓我的畫動起來嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와아! 저도 보고 싶어요!","JPN":"わあ！　私も見たいです！","ENG":"Yay! I’d love to see it happen!","TWN":"哇！我也想看！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"리네, 이렇게 귀엽게 잘 그려졌는데 움직이기까지 하면 더 귀여울 것 같아요!","JPN":"こんなにかわいいマリちゃんの絵が実際に動くとなると、もっとかわいくなりそうですね！","ENG":"Rinae looks so cute here, it’ll be even better if she moves!","TWN":"把璃奈畫得這麼可愛，要是可以動的話一定更可愛！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오옷!? 내가 게임 속에서 움직인다고? 재밌을 것 같은데!?","JPN":"おおっ！？　ウチがゲームの中で動くん？　面白そうやな！？","ENG":"Oh? Me? Moving inside the game? That sounds cool!","TWN":"哇喔！？我可以在遊戲裡動起來嗎？感覺好好玩喔！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보라 양, 혹시 이거 그림 움직이게 할 수 있을까요?","JPN":"シホ君、この絵を動かせますか？","ENG":"Bora, do you think you could rig this?","TWN":"寶拉，你可以讓這個畫動起來嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"가능해요…… 리소스가 더 있다면.","JPN":"できます……リソース、もっとあれば。","ENG":"With more resources… it’s possible.","TWN":"可以……不過需要更多素材。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"박스 군, 혹시 이 정도 퀄리티로 움직이는 그림을 몇 장 더 그려볼 수 있을까요?","JPN":"ダンボール君、このくらいのクオリティで動く絵をあと何枚か描けるかな？","ENG":"Box, could you draw a few more illustrations in this quality?","TWN":"紙箱小朋友，你可以再多畫幾張嗎？品質像這張一樣，然後是動態的。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"자, 잠시만요. 그릴 수는 있을 것 같은데……","JPN":"ま、待ってください。描くのはできると思いますけど……","ENG":"H-hang on. I think I can...","TWN":"我…我想想，是可以畫……"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아무래도 사진이나 모델 같은…… 포즈에 대한 구체적인 이미지가 필요할 것 같아요.","JPN":"なにか写真とかモデルみたいな……ポーズについて具体的なイメージが必要です。","ENG":"But I’m going to have to ask for a more specific reference... like a model or a photo.","TWN":"不過需要像是照片或模特兒……這類有具體動作的畫面。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 로토스코핑을 하고 싶다는 말이구나?","JPN":"あ、ロトスコープがやりたいってことね？","ENG":"You mean you want to try rotoscoping, right?","TWN":"喔，你是說轉描嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그거라면 문제없어! 나랑 리네가 도와줄게!","JPN":"それなら問題ないわ！　私とマリちゃんが手伝ってあげるから！","ENG":"That won’t be a problem! Rinae and I are here to help!","TWN":"那沒問題！我和璃奈可以幫忙！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"로토스 뭐? 그기 뭐꼬?","JPN":"ロトス？　何やそれ。","ENG":"Roto’s what? What’s that?","TWN":"轉什麼？什麼什麼？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"로토스코핑은 카메라로 촬영한 이미지를 그림으로 옮겨 그리는 애니메이션 기법이야.","JPN":"ロトスコープは、カメラで撮影したイメージを絵としてトレースするアニメーションの手法だよ。","ENG":"Rotoscoping is an animation technique where images captured by a camera are traced and drawn as pictures.","TWN":"轉描是指將鏡頭所拍攝下來的畫面，描繪下來的動畫技術。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오오, 뭔지는 몰라도 재밌어 보이는데? 뭘 어떻게 도와주면 되는데?","JPN":"おお、何なのかはわからへんけど面白そうやな。何をどう手伝えばええの？","ENG":"Ooh, sounds excitin’! How can I help?","TWN":"喔喔～雖然聽不太懂，但感覺很好玩，那我該怎麼做？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으음…… 리네는 그냥 평소처럼만 하면 돼.","JPN":"うーん……マリちゃんはただいつも通りにすればいいよ。","ENG":"Um... Just act casual, Rinae.","TWN":"嗯…… 你就跟平常一樣就好。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으잉? 평소처럼 하믄 된다는 게 뭔 말인데?","JPN":"ふえ？　いつも通りって、何やそれ？","ENG":"Hmm? Whaddaya mean by that?","TWN":"啥？跟平常一樣是啥意思？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하아아아아아앗!!","JPN":"はああああああっ！！","ENG":"Haaaaaah!","TWN":"啊啊啊啊啊……！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HYPER_ATTACK_START"},{"id":"L12_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"간데이! 불꽃 베기이이이! 빠샤!","JPN":"行くで！　炎斬りいぃぃ！　うりゃーっ！","ENG":"I’m comin’ for ya! Fire Slash! Hi-ya!","TWN":"去唄，火焰劍～～～！！嘿咻！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아주 좋아, 리네야! 진짜 진짜 귀여워!","JPN":"いいよ、マリちゃん！　めちゃくちゃかわいい！","ENG":"Very good, Rinae! It’s so cute!","TWN":"璃奈，你做得很好！非常可愛！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭔소리고! 이런 상황에선 귀엽다가 아나라 멋있다라고 해야하는 거 아이가!","JPN":"何言ってんねん！　こういう時は、かわいいやなくてカッコいいやろ！","ENG":"What are ya ramblin’ about! I’m supposed to be cool, not cute!","TWN":"你在說什麼！這種時候怎麼會誇我可愛，要說很帥才對唄？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그리고 내는 니가 귀엽다고 하는 거 한 개도 안 믿는데이!","JPN":"それに、ウチはあんたの言うかわいいは絶対信じへんで！","ENG":"Besides, I don’t believe you when ya say something's cute and all!","TWN":"而且每次你說可愛的對象都是些怪物！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후후, 그치만 리네는 뭘 해도 귀여운 걸.","JPN":"ふふ、でもマリちゃんは本当に何をしてもかわいいんだもん。","ENG":"Fu fuu, but you’re always cute, Rinae.","TWN":"呵呵，話是沒錯，但璃奈不管做什麼都很可愛啦。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"좋아, 이번에는 어퍼컷 하듯이 공중으로 폴짝 뛰어볼래?","JPN":"よし、今度はアッパーカットする感じで、空中にぴょんと跳ねてみる？","ENG":"Okay, why don’t you try hopping now, as if you’re pulling an uppercut?","TWN":"好，那接下來換上鉤拳，你要稍微蹦地跳一下。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으으! 그러니까 폴짝이 뭐고 폴짝이! 니는 내가 아직도 얼라인 줄 아나?","JPN":"うう！　だからぴょんはちゃうやろ、ぴょんは！　あんた、ウチがまだ子どもやと思てる？","ENG":"Ugh! Hop? Ya think I’m still a lil girl and all?","TWN":"喂！蹦什麼啦！你真當我是小朋友嗎？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"저기 저 부스 좀 봐, 무슨 촬영회 같은 걸 하나 봐.","JPN":"ねえ、あのブース見て。何か撮影会みたいなのやってるみたい。","ENG":"Look at that booth over there. It looks like they’re doing some kind of a show.","TWN":"欸欸，你看那個攤位，好像在拍什麼東西？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"와, 저 여자애 운동 신경이 엄청 좋은데? 동작 하나하나가 거의 서커스 묘기 수준이잖아?","JPN":"わあ、あの女の子、運動神経抜群じゃん。動きがまるでサーカスみたい。","ENG":"Whoa, that girl’s got some moves! She’s pulling a whole circus out of herself!","TWN":"哇，那女生的運動神經超好，每個動作都像特技表演一樣。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"그런데 대체 무슨 퍼포먼스지? 빗자루를 휘두르면서 기술명을 외치고 있는데!?","JPN":"でも、いったい何のパフォーマンス？　ほうきを振り回しながらスキル名を叫んでるけど！？","ENG":"What performance is it supposed to be, though? It sounds like she’s mocking some kind of skill with a broom.","TWN":"不過那是什麼表演？手上揮著掃把，嘴裡喊著技能名稱！？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 그런 설정의 캐릭터인가보지. 여기 코미페잖아.","JPN":"ま、そんな設定のキャラなんでしょ。ここコミフェだし。","ENG":"Well, that might be her character. We’re at Comic Festival, after all.","TWN":"應該就是在扮演某個角色吧，畢竟這裡是動漫展的嘛。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"즉석에서 포즈 짜고, 행사장에서 사진 촬영까지 밀어붙일 줄은…… 엄청난 실행력이야……!","JPN":"即席でポーズを取って、会場で写真撮影までするとは……とんでもない実行力……！","ENG":"They’re posing and taking pictures from scratch... They’re carrying through...!","TWN":"立刻想好姿勢，然後直接在會場拍起來……真是驚人的執行力……！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"와아! 리네 진짜 너무 귀엽게 잘 나왔어!","JPN":"わあ！　マリちゃん、本当にかわいく撮れたよ！","ENG":"Whoa! You look so cute, Rinae!","TWN":"哇！璃奈，真的超可愛的！"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"자, 이제 박스 군 차례야. 이제 이 사진이랑 영상을 바탕으로 애니메이션을 그리면 돼.","JPN":"はい、今度はダンボール君の番だよ。この写真と映像をもとに、アニメを作ってね。","ENG":"Now it’s your turn, Boxie. Draw an animation sequence out of these photos and videos.","TWN":"現在換你囉，紙箱小朋友，可以參考照片或是影片裡的畫面，把動作畫下來。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네? 네, 알겠어요. 해볼게요.","JPN":"え？　はい、わかりました。やってみます。","ENG":"Huh? Okay. I think I can pull it off.","TWN":"嗯？喔喔，好的，我試試看。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"나한테 넘겨주면 돼…… 애니메이션 제작이 끝나면.","JPN":"私にくれればいい……アニメが作り終わったら。","ENG":"Hand it over to me... when you’re done.","TWN":"畫完後交給我……完成動畫製作後，"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼 플레이할 수 있어…… 테스트 모드이긴 하지만.","JPN":"そしたら、プレイできる……テストモードだけど。","ENG":"Then we can play it... Even if it's in test mode.","TWN":"就可以玩了……不過是測試版。"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"읏차! 그럼 내는 이제 기다리기만 하믄 되는기가?","JPN":"よっし！　じゃあ、ウチはもう待つだけでええんやろ？","ENG":"Gah! Now all that’s left to me is to wait, ain’t it?","TWN":"讚欸！那我現在就等你們完成就好囉？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 어쩐지 두근두근 한데?","JPN":"へへっ、なんだかドキドキするなぁ。","ENG":"Hehe! This is kinda exciting!","TWN":"嘿嘿，有點緊張呢？"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"마, 박스! 이 미리네 님을 따라그린 미리네, 잘 부탁한데이~","JPN":"おい、ダンボール！　このマリ様のトレース、よろしく頼むで～","ENG":"Hey, Box! Take good care of your mini Rinae, will ya?","TWN":"喂，紙箱！要把宓璃奈畫好喔～"},"stage":{"bg":"COMICFESTIVAL","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};